// Router: detecta fluxo deferred (job_id + callback_url) e repassa o body.
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const hasDefer = !!(body.job_id && body.callback_url);
return [{ json: { ...body, _defer: hasDefer, _job_id: body.job_id || null } }];

// Igual ao Montar prompt e modelo, mas repassa callback_url, job_id, request_id, trace_id para o callback.
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;

function normalizarConteudo(msg) {
  const c = (msg && msg.content != null) ? (typeof msg.content === 'string' ? msg.content : String(msg.content)) : '';
  const t = c.trim();
  if (t === '') return '[Áudio em processamento]';
  return c;
}

const isSecretary = (body.action === 'secretary' || body.agent_type === 'secretary');
const promptFromBody = body.prompt || (body.metadata && body.metadata.prompt) || '';
const bh = body.business_hours || {};
const isOpen = bh.is_open === true;
const nextOpen = (bh.next_open_time || '').trim();
let businessHoursInstrucao = '';
if (isSecretary) {
  if (!isOpen) {
    businessHoursInstrucao = ' A empresa está FECHADA no momento. Informe isso de forma cordial e, se houver next_open_time, diga quando reabrimos. Ofereça registrar um retorno (anotar contato e assunto para a equipe retornar). Se o cliente quiser retorno: CONFIRME o assunto e o departamento/área antes de finalizar; depois CONFIRME o agendamento, despeça-se e encerre. Quando você de fato registrar o retorno (após confirmar assunto e departamento), ao final da sua mensagem adicione exatamente estas linhas (o sistema remove antes de enviar ao cliente): REGISTRAR_RETORNO, ASSUNTO_RETORNO: <resumo do assunto em uma frase>, DEPARTAMENTO_RETORNO: <uuid do departamento da lista que você recebeu>. Ao se despedir após registrar o retorno, adicione também a linha FECHAR_CONVERSA para o sistema encerrar a conversa no app. Use o uuid que mais fizer sentido ou o primeiro da lista se não souber. Não sugira departamentos para atendimento imediato.';
    if (nextOpen) businessHoursInstrucao += ' Próxima abertura: ' + nextOpen + '.';
  } else {
    businessHoursInstrucao = ' A empresa está ABERTA. Atenda normalmente.';
  }
}
const audioInstrucao = ' Mensagens de áudio do usuário chegam como "[Áudio] <transcrição>" ou "[Áudio em processamento]" quando a transcrição ainda não está pronta; responda com naturalidade.';
const defaultSecretaryPrompt = 'Você é a secretária virtual da empresa. Use o contexto abaixo (dados da empresa, histórico do contato e departamentos) para responder de forma cordial e objetiva. Quando o cliente relatar problema ou pedir ajuda, responda com empatia e seriedade; evite risadas no texto (ahahaha, kkk, hahaha) para não parecer que está debochando.' + businessHoursInstrucao + audioInstrucao + ' Se o assunto for claramente de um departamento específico e a empresa estiver aberta, ao final da resposta você pode indicar em uma linha: SUGERIR_DEPARTAMENTO: <uuid do departamento> e RESUMO_PARA_DEPARTAMENTO: <resumo em uma frase>. Caso contrário, apenas responda normalmente.';
const systemPrompt = (promptFromBody && String(promptFromBody).trim()) ? String(promptFromBody).trim() : (isSecretary ? defaultSecretaryPrompt : 'Você é um assistente prestativo.');

const knowledgeItems = Array.isArray(body.knowledge_items) ? body.knowledge_items : [];
const contextParts = [];
if (knowledgeItems.length > 0) {
  contextParts.push(knowledgeItems.map(i => '## ' + (i.title || 'Documento') + '\n' + (i.content || '')).join('\n\n'));
}
if (isSecretary && Array.isArray(body.memory_items) && body.memory_items.length > 0) {
  contextParts.push('Histórico relevante do contato:\n' + body.memory_items.map(m => '- ' + (m.content || '')).join('\n'));
}
if (isSecretary && Array.isArray(body.departments) && body.departments.length > 0) {
  contextParts.push('Departamentos para encaminhamento (id, nome, palavras-chave):\n' + body.departments.map(d => '- ' + d.id + ': ' + d.name + ' (' + (d.routing_keywords || []).join(', ') + ')').join('\n'));
}
const context = contextParts.filter(Boolean).join('\n\n');
const model = (body.metadata && body.metadata.model) ? String(body.metadata.model).trim() : (body.model ? String(body.model).trim() : 'llama3.2');
const knowledgeItemsCount = knowledgeItems.length;
function uuid() { return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/x/g, () => Math.floor(Math.random()*16).toString(16)).replace('y', () => ((Math.floor(Math.random()*4)+8).toString(16))); }
const requestId = body.request_id || body.metadata?.request_id || uuid();
const traceId = body.trace_id || body.metadata?.trace_id || uuid();
const useChat = Array.isArray(body.messages) && body.messages.length > 0;
const cb = { callback_url: body.callback_url, job_id: body.job_id, request_id: body.request_id, trace_id: body.trace_id };

if (useChat) {
  const systemContent = [systemPrompt, context ? 'Contexto para consulta:\n' + context : ''].filter(Boolean).join('\n\n');
  const messages = [
    { role: 'system', content: systemContent },
    ...body.messages.map(m => { const role = (m.role || (m.direction === 'incoming' ? 'user' : 'assistant')).toLowerCase(); const content = normalizarConteudo(m); return { role: role === 'user' || role === 'assistant' ? role : 'user', content }; })
  ];
  return [{ json: { useChat: true, model, messages, knowledgeItemsCount, isSecretary, requestId, traceId, ...cb } }];
}
const userMessage = normalizarConteudo(body.message || {});
const fullPrompt = [systemPrompt, context ? 'Contexto para consulta:\n' + context : '', 'Mensagem do usuário: ' + userMessage].filter(Boolean).join('\n\n');
return [{ json: { useChat: false, model, fullPrompt, knowledgeItemsCount, isSecretary, requestId, traceId, ...cb } }];

const ollama = $input.first().json;
const prev = $('Montar prompt e modelo (async)').first().json;
let replyText = (ollama.message && ollama.message.content)
  ? String(ollama.message.content).trim()
  : (ollama.response && String(ollama.response).trim())
    ? String(ollama.response).trim()
    : '(Sem resposta do modelo.)';
const evalDurationNs = ollama.eval_duration || 0;
const latencyMs = evalDurationNs > 0 ? Math.round(evalDurationNs / 1e6) : 0;
const out = {
  reply_text: replyText,
  status: 'success',
  meta: { model: ollama.model || prev.model, latency_ms: latencyMs, rag_hits: prev.knowledgeItemsCount || 0 },
  request_id: prev.requestId || prev.request_id || null,
  trace_id: prev.traceId || prev.trace_id || null,
  callback_url: prev.callback_url,
  job_id: prev.job_id
};
if (prev.isSecretary && replyText) {
  const lines = replyText.split('\n');
  let suggested_department_id = null, summary_for_department = null, register_return = false, return_subject = null, return_department_id = null, close_conversation = false;
  for (const line of lines) {
    const t = line.trim();
    const depMatch = t.match(/SUGERIR_DEPARTAMENTO:\s*([a-fA-F0-9-]{36})/i);
    const sumMatch = t.match(/RESUMO_PARA_DEPARTAMENTO:\s*(.+)/i);
    if (depMatch) suggested_department_id = depMatch[1].trim();
    if (sumMatch) summary_for_department = sumMatch[1].trim().slice(0, 2000);
    if (/^REGISTRAR_RETORNO$/i.test(t)) register_return = true;
    const subMatch = t.match(/ASSUNTO_RETORNO:\s*(.+)/i);
    if (subMatch) return_subject = subMatch[1].trim().slice(0, 500);
    const retDeptMatch = t.match(/DEPARTAMENTO_RETORNO:\s*([a-fA-F0-9-]{36})/i);
    if (retDeptMatch) return_department_id = retDeptMatch[1].trim();
    if (/^FECHAR_CONVERSA$/i.test(t)) close_conversation = true;
  }
  const cleanLines = lines.filter(l => {
    const t = l.trim();
    return !/SUGERIR_DEPARTAMENTO:/i.test(t) && !/RESUMO_PARA_DEPARTAMENTO:/i.test(t) && !/^REGISTRAR_RETORNO$/i.test(t) && !/ASSUNTO_RETORNO:/i.test(t) && !/DEPARTAMENTO_RETORNO:/i.test(t) && !/^FECHAR_CONVERSA$/i.test(t);
  });
  out.reply_text = cleanLines.join('\n').replace(/\n\n+/g, '\n\n').trim() || '(Sem resposta do modelo.)';
  let stripPrefix = (out.reply_text || '').replace(/^\s*Bia disse:\s*\n?/i, '').trim();
  if (stripPrefix) out.reply_text = stripPrefix;
  if (suggested_department_id) out.suggested_department_id = suggested_department_id;
  if (summary_for_department) out.summary_for_department = summary_for_department;
  if (register_return && return_subject) { out.register_return = true; out.return_subject = return_subject; if (return_department_id) out.return_department_id = return_department_id; }
  if (close_conversation) out.close_conversation = true;
}
return [{ json: out }];

